mapper.select:
SELECT wo.order_id, wo.product_id, COALESCE(p.product_name, wo.product_id) AS product_name, wo.status, wo.shortage_status, wo.due_date, wo.order_qty, wo.updated_at FROM work_order wo LEFT JOIN product p ON p.product_id = wo.product_id WHERE wo.is_deleted = 0 AND wo.status IN ('WAITING','READY')
AND ( wo.order_id LIKE CONCAT('%', #{q}, '%') OR wo.product_id LIKE CONCAT('%', #{q}, '%') OR p.product_name LIKE CONCAT('%', #{q}, '%') )
ORDER BY CASE wo.status WHEN 'READY' THEN 1 WHEN 'WAITING' THEN 2 ELSE 9 END, CASE wo.shortage_status WHEN 'CHECKED' THEN 1 WHEN 'DRAFTED' THEN 2 WHEN 'NONE' THEN 3 ELSE 9 END, wo.due_date ASC, wo.updated_at DESC LIMIT #{limit}
